-- Add billing modes, pricing intervals, and usage cost breakdown snapshots.
ALTER TABLE "pricing_rules" ADD COLUMN "billing_mode" character varying NOT NULL DEFAULT 'token';
ALTER TABLE "pricing_rules" ADD COLUMN "per_request_price" character varying NOT NULL DEFAULT '0.00000000';

CREATE TABLE "pricing_intervals" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "pricing_rule_id" bigint NOT NULL,
  "min_tokens" bigint NOT NULL DEFAULT 0,
  "max_tokens" bigint NULL,
  "tier_label" character varying NOT NULL DEFAULT '',
  "image_size" character varying NOT NULL DEFAULT '',
  "input_price_per_million" character varying NOT NULL DEFAULT '0.00000000',
  "output_price_per_million" character varying NOT NULL DEFAULT '0.00000000',
  "cache_read_price_per_million" character varying NOT NULL DEFAULT '0.00000000',
  "cache_write_price_per_million" character varying NOT NULL DEFAULT '0.00000000',
  "per_image_price" character varying NOT NULL DEFAULT '0.00000000',
  PRIMARY KEY ("id")
);
CREATE INDEX "pricinginterval_pricing_rule_id" ON "pricing_intervals" ("pricing_rule_id");
CREATE INDEX "pricinginterval_pricing_rule_id_min_tokens_max_tokens" ON "pricing_intervals" ("pricing_rule_id", "min_tokens", "max_tokens");
CREATE INDEX "pricinginterval_pricing_rule_id_image_size" ON "pricing_intervals" ("pricing_rule_id", "image_size");
CREATE INDEX "pricingrule_billing_mode" ON "pricing_rules" ("billing_mode");

ALTER TABLE "usage_logs" ADD COLUMN "input_cost" character varying NOT NULL DEFAULT '0.00000000';
ALTER TABLE "usage_logs" ADD COLUMN "output_cost" character varying NOT NULL DEFAULT '0.00000000';
ALTER TABLE "usage_logs" ADD COLUMN "cache_read_cost" character varying NOT NULL DEFAULT '0.00000000';
ALTER TABLE "usage_logs" ADD COLUMN "cache_write_cost" character varying NOT NULL DEFAULT '0.00000000';
ALTER TABLE "usage_logs" ADD COLUMN "requested_model" character varying NOT NULL DEFAULT '';
ALTER TABLE "usage_logs" ADD COLUMN "upstream_model" character varying NOT NULL DEFAULT '';
ALTER TABLE "usage_logs" ADD COLUMN "billing_mode" character varying NOT NULL DEFAULT 'token';

-- Historical token-mode rows predate cost breakdown storage. Preserve the
-- invariant that component costs sum to total by assigning legacy cost to input.
UPDATE "usage_logs"
SET "input_cost" = "cost",
    "requested_model" = "model";
